const rows = $input.all();
const row = rows.find(function (i) { return i.json && (i.json.niche || i.json.keywords); }) || (rows[0] || { json: {} });
const j = row.json || {};
const niche = j.niche || 'personal finance';
const business = j.business || '';
const audience = j.audience || '';
const kwRaw = j.keywords || '';
const rawTerms = kwRaw ? String(kwRaw).split(',').map(function (s) { return s.trim(); }).filter(Boolean) : [];
const seen = new Set();
const terms = [];
for (const t of rawTerms) { const k = String(t).toLowerCase(); if (t && !seen.has(k)) { seen.add(k); terms.push(t); } }
const finalTerms = terms.slice(0, 4);
if (finalTerms.length === 0) finalTerms.push(niche);
const orQuery = '(' + finalTerms.map(function (t) { return '"' + t + '"'; }).join(' OR ') + ') lang:en';
return [{ json: { niche: niche, business: business, audience: audience, terms: finalTerms, orQuery: orQuery } }];

