const seen=new Set(); const deduped=[];
for(const r of rows){ const k=r.url||(r.platform+r.caption); if(k&&!seen.has(k)){seen.add(k);deduped.push(r);} }
let niche='your niche', business='', audience='', terms=[];
try { const rn=$('Resolve Niche').first().json; niche=rn.niche||niche; business=rn.business||''; audience=rn.audience||''; terms=rn.terms||[]; } catch(e){}
