for(const r of deduped){ const hay=(String(r.caption)+' '+String(r.author)).toLowerCase(); let rel=0; for(const s of stems){ if(s&&hay.indexOf(s)!==-1)rel++; } r.rel=rel; }
deduped.sort(function(a,b){ if(b.rel!==a.rel)return b.rel-a.rel; return b.views-a.views; });
const top=deduped.slice(0,30);
